python -c "import json,collections; from pathlib import Path; p=Path('output/cognee_codex_full_v2_bundle/edges.jsonl'); field=collections.Counter(); topic=collections.Counter(); approach=collections.Counter(); method=collections.Counter();
for line in p.open():
 o=json.loads(line); t=o['target_id'];
 field[t]+=1 if t.startswith('ResearchField:') else 0; topic[t]+=1 if t.startswith('ResearchTopic:') else 0; approach[t]+=1 if t.startswith('ApproachFamily:') else 0; method[t]+=1 if t.startswith('MethodologicalConcept:') else 0
print('fields', field.most_common(10)); print('topics', topic.most_common(10)); print('approaches', approach.most_common(10)); print('methods', method.most_common(10))"

